const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const action = body.action || 'suspendre';

if (!tenantId || !automationId) {
  return [{ json: { success: false, error: 'tenantId et automationId requis' } }];
}

const newStatus = action === 'annuler' ? 'annulee' : 'suspendue';
const dateField = action === 'annuler' ? 'cancelled_at' : 'suspended_at';

return [{ json: { tenantId, automationId, newStatus, dateField, valid: true } }];

const result = $input.first().json;
const data = $('02. Preparer').first().json;
const label = data.newStatus === 'annulee' ? 'annulee' : 'suspendue';

return [{ json: {
  success: true,
  message: 'Automatisation ' + label
} }];
